class Solution {
public:
    int palindromePartition(string s, int k) {
        int n = s.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));
        for (int i = n - 1; i >= 0; --i) {
            for (int j = i; j < n; ++j) {
                if (s[i] == s[j] && (j - i < 2 || dp[i + 1][j - 1])) {
                    dp[i][j] = 1;
                }
            }
        }
        int res = INT_MAX;
        for (int i = 0; i < n; ++i) {
            if (dp[0][i]) {
                int cnt = 0;
                for (int j = 0; j < i; ++j) {
                    if (s[j] != s[i]) {
                        ++cnt;
                    }
                }
                if (cnt + k <= res) {
                    res = cnt + k;
                }
            }
        }
        return res;
    }
};
